import (
	"container/heap"
)

type Item struct {
	time int64
	node int64
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool { return pq[i].time < pq[j].time }

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}

func solve(n int64, edges [][]int64) int64 {
	adj := make([][]struct{ v, s, e int64 }, n)
	for _, e := range edges {
		u := e[0]
		v := e[1]
		s := e[2]
		e_ := e[3]
		adj[u] = append(adj[u], struct{ v, s, e int64 }{v, s, e_})
	}

	dist := make([]int64, n)
	for i := range dist {
		dist[i] = -1
	}
	dist[0] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{time: 0, node: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		current_time := current.time
		current_node := current.node

		if current_node == n-1 {
			return current_time
		}

		if current_time > dist[current_node] {
			continue
		}

		for _, edge := range adj[current_node] {
			v := edge.v
			s := edge.s
			e := edge.e
			next_time := max(current_time, s) + 1
			if next_time <= e {
				if dist[v] == -1 || next_time < dist[v] {
					dist[v] = next_time
					heap.Push(&pq, &Item{time: next_time, node: v})
				}
			}
		}
	}

	return -1
}
